package ru.memearena.user.api;
import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import ru.memearena.security.CurrentUser; import ru.memearena.user.application.UserProfileService; import java.util.*;
@RestController @RequestMapping("/api/v1/users") public class UserProfileController { private final UserProfileService service; public UserProfileController(UserProfileService service){this.service=service;} @PostMapping("/guest") @Operation(summary="Create guest user") public ResponseEntity<CreateGuestUserResponse> create(@Valid @RequestBody CreateGuestUserRequest r){var created=service.createGuest(r.nickname(),r.installationId(),null); return ResponseEntity.status(HttpStatus.CREATED).body(new CreateGuestUserResponse(UserProfileResponse.from(created.user()),created.accessToken(),created.expiresAt()));} @GetMapping("/me") public UserProfileResponse me(){return UserProfileResponse.from(service.get(CurrentUser.required().userId()));} @PostMapping("/me/logout") public ResponseEntity<Void> logout(){service.logout(CurrentUser.required().sessionId()); return ResponseEntity.noContent().build();} @GetMapping("/{userId}") @Operation(summary="Get public user profile") public UserProfileResponse get(@PathVariable UUID userId){return UserProfileResponse.from(service.get(userId));} }
